        if (compare_map<DO_AREA>(worst_arrival, best_arrival, area_local, best_area_flow, cut->size(), best_size)) {
          best_arrival = worst_arrival;
          best_area_flow = area_local;
          best_size = cut->size();
          best_cut = cut_index;
          best_area = gate.area;
          best_phase = gate_polarity;
          best_supergate = &gate;
        } else if (temperature > 0.1) {
          // Weighted probabilistic acceptance considering search progress
          double progress = min(1.0, iteration/5000.0);
          double arrival_weight = 0.7 * (1.0 - progress) + 0.3; // Favor timing early, balance later
          double area_weight = 1.0 - arrival_weight;
          double delta = arrival_weight * (worst_arrival - best_arrival)/best_arrival + 
                       area_weight * (area_local - best_area_flow)/best_area_flow;
          double acceptance_prob = exp(-delta / (temperature * sqrt(1.0 + iteration/10000.0)));
          if ((double)rand()/RAND_MAX < acceptance_prob) {
            best_arrival = worst_arrival;
            best_area_flow = area_local;
            best_size = cut->size();
            best_cut = cut_index;
            best_area = gate.area;
            best_phase = gate_polarity;
            best_supergate = &gate;
          }
        }
        // Cool down temperature
        temperature *= cooling_rate;
      }

      ++cut_index;
    }

    // Adaptive temperature control based on solution diversity
    iteration++;
    static int stagnation_count = 0;
    static double last_best = best_arrival;
    static double diversity = 0.0;

    // Calculate solution diversity
    double current_diversity = fabs(best_arrival - last_best);
    diversity = 0.9 * diversity + 0.1 * current_diversity;

    if (diversity < epsilon * 0.1 || temperature < 0.01) {
