        double boost_factor = 1.0 + (1.0 - (diversity / (epsilon * 0.1)));
        temperature = initial_temp * (0.5 + 0.5*(double)rand()/RAND_MAX) * boost_factor;
        cooling_rate = 0.8 + 0.2*(double)rand()/RAND_MAX;
        stagnation_count = 0;
