            temperature = initial_temp * (0.5 + 0.5*(double)rand()/RAND_MAX);
            cooling_rate = 0.9 + 0.1*(double)rand()/RAND_MAX;
            stagnation_count = 0;
        }
    } else {
        stagnation_count = 0;
    }
